# ── Test 3: Parallel execution ──────────────────────────────
echo "Test 3: Parallel entry nodes converge"
WF3=$(create_workflow '{
  "name": "e2e-parallel",
  "definition": { "nodes": [
    { "id": "branch-a", "type": "script", "config": { "runtime": "bash", "script": "echo A" }, "next": "end" },
    { "id": "branch-b", "type": "script", "config": { "runtime": "bash", "script": "echo B" }, "next": "end" },
    { "id": "end", "type": "notify", "config": { "channel": "swarm", "template": "Done" } }
  ]}
}')
# Two entry nodes (no predecessors) execute in parallel, then converge on end
RUN3=$(trigger_workflow "$WF3")
STATUS3=$(wait_run "$RUN3")
STEPS3=$(get_run "$RUN3" | jq '.steps | length')
assert_eq "run completes" "$STATUS3" "completed"
assert_eq "3 steps executed (2 branches + end)" "$STEPS3" "3"

